import {
  BrowserRouter,
  Routes,
  Route
} from 'react-router-dom';

import AdminLogin from './pages/AdminLogin';

function App() {

  return (

    <BrowserRouter>

      <Routes>

        <Route
          path="/admin-login"
          element={<AdminLogin />}
        />

      </Routes>

    </BrowserRouter>

  );

}

export default App;
